example_bad:
#![feature(intrinsics)]

extern "rust-intrinsic" {
    fn my_custom_intrinsic(); // Error: unrecognized intrinsic
}

fixes.code:
#![feature(intrinsics)]

extern "rust-intrinsic" {
    fn size_of<T>() -> usize; // This is a real intrinsic
}

// Instead of using intrinsics directly:
let size = std::mem::size_of::<i32>();
let aligned = std::mem::align_of::<i32>();
